import { ipcMain, BrowserWindow } from 'electron';
import {
  IPC_CHANNELS,
  OneClickTemplateIdSchema,
  OneClickPrereqSchema,
  OneClickInstallSchema,
  OneClickSendInputSchema,
  OneClickServerIdSchema,
  OneClickInstallationIdSchema,
  OneClickLogsSchema,
  OneClickExecuteActionSchema,
  OneClickGetActionOptionsSchema,
  ApiResult,
} from './types';
import { oneClickService } from '../services/OneClickService';
import type {
  OneClickTemplate,
  OneClickInstallation,
  PrereqResult,
  ServiceStatus,
  ActionResult,
  TemplateAction,
} from '../services/OneClickService';

export function registerOneClickHandlers() {
  // ============ Templates ============

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_GET_TEMPLATES,
    async (): Promise<ApiResult<OneClickTemplate[]>> => {
      try {
        const templates = oneClickService.getTemplates();
        return { success: true, data: templates };
      } catch (error) {
        console.error('Error getting one-click templates:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_GET_TEMPLATE,
    async (_event, input): Promise<ApiResult<OneClickTemplate | null>> => {
      try {
        const { templateId } = OneClickTemplateIdSchema.parse(input);
        const template = oneClickService.getTemplate(templateId);
        return { success: true, data: template };
      } catch (error) {
        console.error('Error getting one-click template:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Prerequisites ============

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_CHECK_PREREQUISITES,
    async (_event, input): Promise<ApiResult<PrereqResult>> => {
      try {
        const { serverId, templateId } = OneClickPrereqSchema.parse(input);
        const result = await oneClickService.checkPrerequisites(serverId, templateId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error checking prerequisites:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Installation ============

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_INSTALL,
    async (_event, input): Promise<ApiResult<{ installationId: string }>> => {
      try {
        const { serverId, templateId } = OneClickInstallSchema.parse(input);
        const window = BrowserWindow.getAllWindows()[0];
        if (!window) throw new Error('No browser window available');
        const result = await oneClickService.install(serverId, templateId, window);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error starting one-click install:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_SEND_INPUT,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { installationId, input: userInput } = OneClickSendInputSchema.parse(input);
        oneClickService.sendInput(installationId, userInput);
        return { success: true, data: undefined };
      } catch (error) {
        console.error('Error sending input:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Queries ============

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_GET_INSTALLATIONS,
    async (_event, input): Promise<ApiResult<OneClickInstallation[]>> => {
      try {
        const { serverId } = OneClickServerIdSchema.parse(input);
        const installations = oneClickService.getInstallations(serverId);
        return { success: true, data: installations };
      } catch (error) {
        console.error('Error getting installations:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_GET_INSTALLATION,
    async (_event, input): Promise<ApiResult<OneClickInstallation | null>> => {
      try {
        const { installationId } = OneClickInstallationIdSchema.parse(input);
        const installation = oneClickService.getInstallation(installationId);
        return { success: true, data: installation };
      } catch (error) {
        console.error('Error getting installation:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Lifecycle ============

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_START,
    async (_event, input): Promise<ApiResult<{ stdout: string; stderr: string; exitCode: number }>> => {
      try {
        const { serverId, installationId } = OneClickInstallationIdSchema.parse(input);
        const result = await oneClickService.start(serverId, installationId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error starting service:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_STOP,
    async (_event, input): Promise<ApiResult<{ stdout: string; stderr: string; exitCode: number }>> => {
      try {
        const { serverId, installationId } = OneClickInstallationIdSchema.parse(input);
        const result = await oneClickService.stop(serverId, installationId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error stopping service:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_RESTART,
    async (_event, input): Promise<ApiResult<{ stdout: string; stderr: string; exitCode: number }>> => {
      try {
        const { serverId, installationId } = OneClickInstallationIdSchema.parse(input);
        const result = await oneClickService.restart(serverId, installationId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error restarting service:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_STATUS,
    async (_event, input): Promise<ApiResult<ServiceStatus>> => {
      try {
        const { serverId, installationId } = OneClickInstallationIdSchema.parse(input);
        const status = await oneClickService.getStatus(serverId, installationId);
        return { success: true, data: status };
      } catch (error) {
        console.error('Error getting status:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_LOGS,
    async (_event, input): Promise<ApiResult<string>> => {
      try {
        const { serverId, installationId, lines } = OneClickLogsSchema.parse(input);
        const logs = await oneClickService.getLogs(serverId, installationId, lines);
        return { success: true, data: logs };
      } catch (error) {
        console.error('Error getting logs:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_UPDATE,
    async (_event, input): Promise<ApiResult<{ stdout: string; stderr: string; exitCode: number }>> => {
      try {
        const { serverId, installationId } = OneClickInstallationIdSchema.parse(input);
        const result = await oneClickService.update(serverId, installationId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error updating service:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_UNINSTALL,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId, installationId } = OneClickInstallationIdSchema.parse(input);
        await oneClickService.uninstall(serverId, installationId);
        return { success: true, data: undefined };
      } catch (error) {
        console.error('Error uninstalling service:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Actions ============

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_GET_ACTIONS,
    async (_event, input): Promise<ApiResult<TemplateAction[]>> => {
      try {
        const { templateId } = OneClickTemplateIdSchema.parse(input);
        const actions = oneClickService.getActions(templateId);
        return { success: true, data: actions };
      } catch (error) {
        console.error('Error getting actions:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_EXECUTE_ACTION,
    async (_event, input): Promise<ApiResult<ActionResult>> => {
      try {
        const { serverId, installationId, actionId, inputs } = OneClickExecuteActionSchema.parse(input);
        const result = await oneClickService.executeAction(serverId, installationId, actionId, inputs);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error executing action:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.ONE_CLICK_GET_ACTION_OPTIONS,
    async (_event, input): Promise<ApiResult<string[]>> => {
      try {
        const { serverId, templateId, actionId, inputName } = OneClickGetActionOptionsSchema.parse(input);
        const options = await oneClickService.getActionOptions(serverId, templateId, actionId, inputName);
        return { success: true, data: options };
      } catch (error) {
        console.error('Error getting action options:', error);
        return { success: false, error: String(error) };
      }
    }
  );
}
